// Claudeway'den gelen result text'ini parse et
const resultText = $input.first().json.result || $input.first().json.text || '';

// JSON bloğunu bul
let jsonStr = resultText;
const jsonMatch = resultText.match(/```json\s*([\s\S]*?)```/);
if (jsonMatch) {
  jsonStr = jsonMatch[1].trim();
} else {
  // JSON objesini direkt bulmaya çalış
  const objMatch = resultText.match(/\{[\s\S]*\}/);
  if (objMatch) {
    jsonStr = objMatch[0];
  }
}

const analysis = JSON.parse(jsonStr);

// Orijinal issue bilgilerini de ekle
const issue = $('Only Opened Issues').first().json.body.issue;

const typeEmoji = analysis.type === 'bug' ? '🐛' : '✨';
const priorityEmoji = { high: '🔴', medium: '🟡', low: '🟢' }[analysis.priority] || '⚪';
const complexityMap = { simple: 'Basit', moderate: 'Orta', complex: 'Karmaşık' };

// Slack mesajı oluştur
const todoFormatted = analysis.todo_list.map((item, i) => `${i + 1}. ${item}`).join('\n');

const slackMessage = `${typeEmoji} *${analysis.type === 'bug' ? 'Bug Report' : 'Feature Request'}* ${priorityEmoji} ${analysis.priority.toUpperCase()}

*Issue:* <${issue.html_url}|#${issue.number} - ${issue.title}>
*Açıklayan:* ${issue.user.login}
*Karmaşıklık:* ${complexityMap[analysis.estimated_complexity] || analysis.estimated_complexity}

> ${analysis.summary}

*Neden ${analysis.type}:* ${analysis.reasoning}

📋 *Yapılacaklar:*
${todoFormatted}`;

return [{
  json: {
    ...analysis,
    issue_number: issue.number,
    issue_title: issue.title,
    issue_url: issue.html_url,
    slack_message: slackMessage
  }
}];
